1	export type Cell = [number, number];
2	
3	const encode = ([x, y]: Cell): string => `${x},${y}`;
4	const decode = (key: string): Cell => {
5	  const [x, y] = key.split(",");
6	  return [Number(x), Number(y)];
7	};
8	
9	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
10	  [-1, -1], [-1, 0], [-1, 1],
11	  [ 0, -1],          [ 0, 1],
12	  [ 1, -1], [ 1, 0], [ 1, 1],
13	];
14	
15	const survives = (count: number, wasAlive: boolean): boolean =>
16	  count === 3 || (count === 2 && wasAlive);
17	
18	export function nextGeneration(liveCells: Cell[]): Cell[] {
19	  const liveSet = new Set(liveCells.map(encode));
20	  const neighborCounts = new Map<string, number>();
21	
22	  for (const [x, y] of liveCells) {
23	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
24	      const key = encode([x + dx, y + dy]);
25	      neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
26	    }
27	  }
28	
29	  const result: Cell[] = [];
30	  for (const [key, count] of neighborCounts) {
31	    if (survives(count, liveSet.has(key))) {
32	      result.push(decode(key));
33	    }
34	  }
35	  return result;
36	}
37

1	import { describe, it, expect } from "vitest";
2	import { nextGeneration, type Cell } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("empty grid returns empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("single live cell dies from underpopulation (0 neighbors) — [(0,0)] → []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("two adjacent live cells both die from underpopulation (1 neighbor each) — [(0,1),(1,1)] → []", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("block still life remains unchanged — [(0,0),(1,0),(0,1),(1,1)] → same", () => {
15	    const result = nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]]);
16	    expect(new Set(result.map((c) => c.join(",")))).toEqual(
17	      new Set(["0,0", "1,0", "0,1", "1,1"]),
18	    );
19	  });
20	  it("live cell with 4 neighbors dies from overpopulation (plus pattern center)", () => {
21	    const plus: Cell[] = [[1, 1], [0, 1], [2, 1], [1, 0], [1, 2]];
22	    const result = nextGeneration(plus);
23	    const resultSet = new Set(result.map((c) => c.join(",")));
24	    expect(resultSet.has("1,1")).toBe(false);
25	  });
26	  it("dead cell with exactly 3 live neighbors becomes alive (reproduction) — L-shape grows to block", () => {
27	    const lShape: Cell[] = [[0, 0], [1, 0], [0, 1]];
28	    const result = nextGeneration(lShape);
29	    const resultSet = new Set(result.map((c) => c.join(",")));
30	    expect(resultSet).toEqual(new Set(["0,0", "1,0", "0,1", "1,1"]));
31	  });
32	  it("blinker oscillates from vertical to horizontal — [(0,0),(0,1),(0,2)] → [(-1,1),(0,1),(1,1)]", () => {
33	    const result = nextGeneration([[0, 0], [0, 1], [0, 2]]);
34	    expect(new Set(result.map((c) => c.join(",")))).toEqual(
35	      new Set(["-1,1", "0,1", "1,1"]),
36	    );
37	  });
38	  it("handles negative coordinates correctly — block at negatives survives", () => {
39	    const result = nextGeneration([[-2, -2], [-1, -2], [-2, -1], [-1, -1]]);
40	    expect(new Set(result.map((c) => c.join(",")))).toEqual(
41	      new Set(["-2,-2", "-1,-2", "-2,-1", "-1,-1"]),
42	    );
43	  });
44	});
